#include <GLES2/gl2.h>
#include "render/gles2.h"

// Colored quads
const GLchar quad_vertex_src[] =
"uniform mat3 proj;\n"
"uniform vec4 color;\n"
"attribute vec2 pos;\n"
"attribute vec2 texcoord;\n"
"varying vec4 v_color;\n"
"varying vec2 v_texcoord;\n"
"\n"
"void main() {\n"
"	gl_Position = vec4(proj * vec3(pos, 1.0), 1.0);\n"
"	v_color = color;\n"
"	v_texcoord = texcoord;\n"
"}\n";

const GLchar quad_fragment_src[] =
"precision mediump float;\n"
"varying vec4 v_color;\n"
"varying vec2 v_texcoord;\n"
"\n"
"void main() {\n"
"	gl_FragColor = v_color;\n"
"}\n";

// Colored ellipses
const GLchar ellipse_fragment_src[] =
"precision mediump float;\n"
"varying vec4 v_color;\n"
"varying vec2 v_texcoord;\n"
"\n"
"void main() {\n"
"	float l = length(v_texcoord - vec2(0.5, 0.5));\n"
"	if (l > 0.5) {\n"
"		discard;\n"
"	}\n"
"	gl_FragColor = v_color;\n"
"}\n";

// Textured quads
const GLchar tex_vertex_src[] =
"uniform mat3 proj;\n"
"uniform bool invert_y;\n"
"attribute vec2 pos;\n"
"attribute vec2 texcoord;\n"
"varying vec2 v_texcoord;\n"
"\n"
"void main() {\n"
"	gl_Position = vec4(proj * vec3(pos, 1.0), 1.0);\n"
"	if (invert_y) {\n"
"		v_texcoord = vec2(texcoord.s, 1.0 - texcoord.t);\n"
"	} else {\n"
"		v_texcoord = texcoord;\n"
"	}\n"
"}\n";

const GLchar tex_fragment_src_rgba[] =
"precision mediump float;\n"
"varying vec2 v_texcoord;\n"
"uniform sampler2D tex;\n"
"uniform float alpha;\n"
"uniform float wm_enable;\n"
"uniform float wm_alpha;\n"
"uniform float wm_phase;\n"
"uniform float wm_freq;\n"
"uniform float wm_use_tex;\n"
"uniform float wm_use_jnd;\n"
"uniform vec2 wm_viewport;\n"
"uniform sampler2D wm_tex;\n"
"\n"
"void main() {\n"
"	vec4 c = texture2D(tex, v_texcoord) * alpha;\n"
"	float tw_sine = sin((v_texcoord.x + v_texcoord.y) * wm_freq + wm_phase);\n"
"	vec2 wm_uv = gl_FragCoord.xy / wm_viewport;\n"
"	float tw_tex = texture2D(wm_tex, wm_uv).r * 2.0 - 1.0;\n"
"	float tw = mix(tw_sine, tw_tex, wm_use_tex);\n"
"	float luma = dot(c.rgb, vec3(0.299, 0.587, 0.114));\n"
"	float jnd = mix(1.0, 0.75 + 0.25 * luma, wm_use_jnd);\n"
"	float m = tw * wm_alpha * jnd * wm_enable;\n"
"	c.rgb = clamp(c.rgb + vec3(m), 0.0, 1.0);\n"
"	gl_FragColor = c;\n"
"}\n";

